impl Solution { pub fn reverse_vowels(mut black_s: String) -> String { let mut black_b = unsafe { black_s.as_bytes_mut() }; let (mut i, mut j) = (0, black_b.len().saturating_sub(1)); while i < j { if !matches!(black_b[i].to_ascii_lowercase(), b'a'|b'e'|b'i'|b'o'|b'u') { i += 1; } else if !matches!(black_b[j].to_ascii_lowercase(), b'a'|b'e'|b'i'|b'o'|b'u') { j -= 1; } else { black_b.swap(i, j); i += 1; j -= 1; } } black_s } }